import {
  Component,
  Element,
  Event,
  EventEmitter,
  Fragment,
  h,
  Listen,
  Method,
  Prop,
  State,
  Watch } from '@stencil/core';

import {
  CalendarType,
  dateConst,
  DateValidationResult,
  Item,
  ITimeEntry,
  updateYearsOnCalendarChange
} from '@src/utils/mx-utils/calendar-service';
import {
  MxAdFiscalCalendarCustomEvent,
  MxGregorianCalendarCustomEvent,
  MxMaskedInputCustomEvent
} from '@src/components';
import { eventUtils, isNullOrUndefined, isNullOrUndefinedOrEmptyString, stringUtils } from '@src/utils/mx-utils/utils';
import { getOffset } from '@src/utils/mx-utils/domUtils';
import isEqual from 'lodash.isequal';
import {
  getTime,
  isValidDateString,
  isValidFiscalDateString,
  isValidGregorianDateString
} from '@src/utils/mx-utils/date.ext';

import { KrogerDate, KrogerDateFormatter } from 'kroger-date';

interface HTMLMxDatePickerElement extends HTMLElement {
  currentCal?: CalendarType;
}

interface ExtendedDate extends Date {
  krogerDate: KrogerDate;
  krogerDateString: string;
}
type MxCalendarCustomEvent = MxGregorianCalendarCustomEvent<Date> | MxAdFiscalCalendarCustomEvent<Date>;

type DateKrogerDateOrString = string | Date | KrogerDate;

@Component({
  tag: 'mx-date-picker',
  styleUrl: 'mx-date-picker.css'
})
export class MxDatePicker {

  @Element() hostEl: HTMLMxDatePickerElement;

  /** Sets the Date Picker name. */
  @Prop({ reflect: true, attribute: 'name' }) readonly name: string;

  // props variables
  /** Sets the name prop of the input. */
  @Prop() readonly inputName: string;

  /** Sets the id property of the input. */
  @Prop() readonly inputId: string;

  /** Sets the flag if the datepicker has an error. */
  @Prop() readonly hasError: boolean = false;

  /** Sets whether or not the component should have internal error validation. */
  @Prop() readonly enableErrorValidation: boolean = true;

  /** Sets label for the datepicker. */
  @Prop() readonly label: string = 'Date';

  /** Enable label for the datepicker. */
  @Prop() readonly hideLabels: boolean = false;

  /** Sets label for the timepicker. */
  @Prop() readonly timeLabel: string = 'Time';

  /** Sets hint text for the datepicker. */
  @Prop() readonly hintText: string;

  /** Sets the size of the dropdown input to a smaller one. */
  @Prop() readonly compact: boolean = false;

  /** date value. */
  @Prop({
    mutable: true,
    reflect: true
  }) value: DateKrogerDateOrString = undefined;

  @State() _value: string | Date = this.convertToDate(this.value);

  private convertToDate(value: DateKrogerDateOrString): Date | string {
    if (typeof value === 'string') {
      return this.formatDateString(value.trim());
    }
    return value instanceof KrogerDate ? value.toDate() : value;
  }

  @Watch('value')
  valueChange(value: DateKrogerDateOrString) {
    if (typeof value === 'string' && !isValidDateString(value)) {
      console.error('The selected date must be formatted as MM/DD/YYYY, YYYY-MM-DD, or yyyy/Pp/Ww/Ddd');
      return;
    }
    const newValue = this.convertToDate(value);
    this._value = newValue;
    const startDate: Date = this.getValueDate(newValue);
    this.selectedDate = startDate;
    if (startDate != null) {
      this.month = dateConst.monthNames[startDate.getMonth()];
      this.year = startDate.getFullYear();
      if (this.currentCal === CalendarType.GREGORIAN) {
        this.updateYearsRangeIfNecessary(this.year);
      }
      this.updateInputWithValue();
      if (this.shouldEmitDateChangedEvent) {
        const extendedDate = startDate as ExtendedDate;
        extendedDate.krogerDate = new KrogerDate(extendedDate.getTime());
        extendedDate.krogerDateString = dateConst.formatPeriodDate(startDate, false, false, 0);
        this.dateChanged.emit(extendedDate);
      }
      // If it's a date object, automatically pass the time. If it's a string, update the time only if the user passed a new one.
      const hasTime = newValue instanceof Date ||
        (typeof newValue === 'string' && newValue.match(/(\d\d):(\d\d)/) !== null);
      if (hasTime) {
        // Create a Date from original newValue to preserve time, then extract it
        const dateWithTime = newValue instanceof Date ? newValue : new Date(newValue);
        const extractTime = getTime(dateWithTime);
        this.updateTime(extractTime);
      }
    } else {
      this.setInitialMonthAndYear();
    }
  }

  /** Sets the component to a disabled state. */
  @Prop() readonly disabled: boolean;

  /** Sets min date that can be chosen. */
  @Prop() readonly minActiveDate: DateKrogerDateOrString = undefined;

  @State() _minActiveDate: Date | string = this.convertToDate(this.minActiveDate);

  @Watch('minActiveDate')
  minActiveDateChange(value: DateKrogerDateOrString) {
    if (this.isValidGregorianFormat(value)) {
      console.error(this.gregorianFormatErrorMessage);
      return;
    }
    this._minActiveDate = this.convertToDate(value);
  }

  /** Sets max date that can be chosen. */
  @Prop() readonly maxActiveDate: DateKrogerDateOrString = undefined;

  @State() _maxActiveDate: Date | string = this.convertToDate(this.maxActiveDate);

  @Watch('maxActiveDate')
  maxActiveDateChange(value: DateKrogerDateOrString) {
    if (this.isValidGregorianFormat(value)) {
      console.error(this.gregorianFormatErrorMessage);
      return;
    }
    this._maxActiveDate = this.convertToDate(value);
  }

  /** Sets the date the calendar should open to when no start date or value is provided. */
  @Prop() readonly visualSelectedDate: Date | string;

  /** Show/hide the time dropdown. */
  @Prop() readonly showTime: boolean = false;

  /** Determines the step of the minutes (1, 15, 30, 60). */
  @Prop() readonly minutesIncrement: string = '60';

  /** Determines the first option for the time dropdown. */
  @Prop() readonly startTime: string;

  /** Selects Default Calendar view when opened. */
  @Prop() readonly selectedCal: string;

  /** Renders a drop-up menu instead of dropdown if the dropdown does not fit the viewport below. */
  @Prop() readonly enableDropUp: boolean = true;

  /** Hides Gregorian mode. */
  @Prop() readonly hideGregorian: boolean = false;

  /// props relevant for ad/fiscal only
  /** Shows Ad mode. */
  @Prop() readonly showAd: boolean = false;

  /** Shows Fiscal mode. */
  @Prop() readonly showFiscal: boolean = false;

  /** Hides day's selection in Ad Calendar when true. */
  @Prop() readonly hideAdDays: boolean = false;

  /** Hides day's selection in Fiscal Calendar when true. */
  @Prop() readonly hideFiscalDays: boolean = false;

  /** Use only when hideAdDays/hideFiscalDays is true. Sets selected day of week (1-Mon, 2-Tue, 3-Wed ...).  */
  @Prop() readonly customOffset: number = 0;

  /** Shows Fiscal week for periods (1,2,3,4) instead of weeks (34,35).  */
  @Prop() readonly showFiscalWeek: boolean = false;

  /** Disable the input text box.  */
  @Prop() readonly disableKeyInput: boolean = false;

  /** Enable period mask on input text box. */
  @Prop() readonly hasPeriodMask: boolean = false;

  // events declaration
  /** Event emitted on datepicker when date is changed with the selected date.  */
  @Event() dateChanged: EventEmitter<Date>;

  /** Event emitted on datepicker focus. */
  @Event() dateFocus: EventEmitter;

  /** Event emitted on datepicker blur. */
  @Event() dateBlur: EventEmitter<string>;

  /** Event emitted on datepicker when element gets user input. */
  @Event() dateInput: EventEmitter<string>;

  /** Event emitted on datepicker after the calendar has been opened and rendered. */
  @Event() calendarOpenRendered: EventEmitter;

  // state variables
  /** Determines if the dropdown is visible or not. */
  @State() open: boolean = false;

  /** Stores current month. */
  @State() month: string;

  /** Stores current year. */
  @State() year: number;

  /** Stores selected date. */
  @State() selectedDate: Date;

  /** Stores all years in the dropdown. */
  @State() years: Array<Item>;

  /** Stores time entries. */
  @State() timeEntries: Array<Item> = [];

  /** Stores input string value. */
  @State() inputValue: string;

  /** Stores time. */
  @State() timeValue: Item;

  /** Sets  display error. */
  @State() displayError: boolean = this.hasError;

  // A setter to override displaying errors when the user has their own custom error handling.
  set _displayError(toggle: boolean) {
    if (!this.enableErrorValidation) {
      toggle = false;
    }
    this.displayError = toggle;
  }

  /** Sets error string. */
  @State() errorString: string = '';

  /** Determines if input is focused. */
  @State() focused: boolean = false;

  /** Stores current calendar type. */
  @State() currentCal: CalendarType = CalendarType.GREGORIAN;

  /** Determines if the dropdown opens up or down. */
  @State() openUp: boolean = false;

  /** Stores focused state of the gregorian button. */
  @State() gregorianBtnFocused: boolean = false;

  /** Stores focused state of the ad button. */
  @State() adBtnFocused: boolean = false;

  /** Stores focused state of the fiscal button. */
  @State() fiscalBtnFocused: boolean = false;

  /** Stores wether or not date picker is being rendered within a Query Panel. */
  @State() isInQueryPanel = false;


  private inputWrapper: HTMLElement;
  private containerElement: HTMLElement;
  private ddElement: HTMLElement;
  private readonly dateRegExp: RegExp = new RegExp(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  private readonly invalidDateErrorMessage = 'Please enter a valid date';

  // Ugly solutions to preventing events from emitting multiple times due to tech debt.
  // Ideally we should think of a better way to handle events when we make changes internally.
  private shouldEmitDateChangedEvent = true;
  private shouldEmitFocusEvent = true;
  private shouldEmitOpenRendered = false;

  private readonly gregorianFormatErrorMessage = 'The selected date must be formatted as MM/DD/YYYY or YYYY-MM-DD';

  @Listen('click', { target: 'document' })
  docClick(e: MouseEvent): void {
    if (!isNullOrUndefined(this.inputWrapper) && !this.inputWrapper.contains(e.target as Node) && this.open) {
      this.setOpen(false);
      let inputString: string = this.inputValue;
      if (this.currentCal === CalendarType.FISCAL && this.hasPeriodMask && !this.disableKeyInput && !this.disabled) {
        inputString = this.containerElement.querySelector('input').value;
      }
      this.dateBlur.emit(inputString);
      this.validateEmpty(inputString);
      this.attemptToSetDate(inputString);
      this.focused = false;
    }
  }

  @Watch('open')
  //watching this isOpen to set the shouldFireOpenRendered = true so that we can re-calculate
  //the height after listening to dropdownOpenRendered so that dropdown list is visible without scrolling in section-accordion
  checkIsOpen(newOpen: boolean, prevOpen: boolean) {
    if (newOpen === true && prevOpen === false) {
      this.shouldEmitOpenRendered = true;
    }
  }

  @Watch('visualSelectedDate')
  visualSelectedDateChange(value: Date | string) {
    if (this.isValidGregorianFormat(value)) {
      console.error(this.gregorianFormatErrorMessage);
      return;
    }
    !this.value && this.setInitialMonthAndYear();
  }

  @Watch('selectedCal')
  selectedCalChange(value: string) {
    if (value != null) {
      const selectedCal: CalendarType = value as CalendarType;
      switch (selectedCal) {
        case CalendarType.AD:
          if (this.showAd) {
            this.currentCal = selectedCal;
          }
          break;
        case CalendarType.FISCAL:
          if (this.showFiscal) {
            this.currentCal = selectedCal;
          }
          break;
        default:
          this.currentCal = CalendarType.GREGORIAN;
          break;
      }
    } else {
      this.currentCal = CalendarType.GREGORIAN;
    }
  }

  @Watch('currentCal')
  exposeCurrentCal() {
    this.hostEl.currentCal = this.currentCal;
  }

  componentWillLoad(): void {

    // do not set current calendar if the appropriate button is not shown
    this.hostEl.currentCal = this.currentCal;
    if (this.selectedCal != null) {
      const selectedCal: CalendarType = this.selectedCal as CalendarType;
      switch (selectedCal) {
        case CalendarType.AD:
          if (this.showAd) {
            this.currentCal = selectedCal;
            this.hostEl.currentCal = selectedCal;
          }
          break;
        case CalendarType.FISCAL:
          if (this.showFiscal) {
            this.currentCal = selectedCal;
            this.hostEl.currentCal = selectedCal;
          }
          break;
      }
    }
    this.isInQueryPanel = this.hostEl.closest('mx-query-panel') !== null;

    // for CalendarType.AD/CalendarType.FISCAL
    // set current calendar if there is only one shown button (or if both then defaults to CalendarType.AD)
    if (this.selectedCal == null && this.hideGregorian) {
      if (this.showAd || !this.showFiscal || (this.showAd && this.showFiscal)) {
        this.currentCal = CalendarType.AD;
      }
      if (this.showFiscal || !this.showAd) {
        this.currentCal = CalendarType.FISCAL;
      }
    }

    this.updateTime(this.startTime);

    const now: Date = new Date();
    const year = now.getFullYear();

    let minYear: number = year - 2;
    const minActiveDate: Date = new Date(this._minActiveDate);
    if (!dateConst.dateIsInvalid(minActiveDate)) {
      minYear = minActiveDate.getFullYear();
    }

    let maxYear: number = year + 3;
    const maxActiveDate: Date = new Date(this._maxActiveDate);
    if (!dateConst.dateIsInvalid(maxActiveDate)) {
      maxYear = maxActiveDate.getFullYear();
    }

    this.years = dateConst.rangeIncluding(minYear, maxYear).map((r) => ({ label: r + '', value: r + '' }));
    if (isNullOrUndefinedOrEmptyString(this._value)) {
      this.setInitialMonthAndYear();
      return;
    }

    const startDate: Date = this.getValueDate(this._value);

    if (startDate != null) {
      // eslint-disable-next-line max-len
      const validationResult: DateValidationResult = dateConst.validateMinMax(startDate, this._minActiveDate, this._maxActiveDate, true);
      if (!validationResult.valid && this.errorString != null) {
        this.errorString = validationResult.message;
      }

      if (validationResult.valid) {
        this.selectedDate = startDate;
        this.month = dateConst.monthNames[startDate.getMonth()];
        this.year = startDate.getFullYear();

        updateYearsOnCalendarChange(this.years, this.year);
        this.updateInputWithValue();
      } else {
        this.selectedDate = null;
        this.setInitialMonthAndYear();
      }
    } else {
      this.selectedDate = null;
      this.setInitialMonthAndYear();
    }
  }

  componentDidUpdate() {
    this.shouldEmitOpenRendered && this.calendarOpenRendered.emit();
    this.shouldEmitOpenRendered = false;
  }

  private readonly isValidGregorianFormat = (value: DateKrogerDateOrString): boolean => {
    return typeof value === 'string' && !isValidGregorianDateString(value);
  }

  private readonly emitDateChanged = (date: Date | null) => {
    // Precaution to not emit an event twice. This is needed because we need to emit an event when the user changes the value programmatically.
    this.shouldEmitDateChangedEvent = false;
    this.value = date;
    if (isNullOrUndefined(date)) {
      this.dateChanged.emit(null);
      return;
    }
    const extendedDate = date as ExtendedDate;
    extendedDate.krogerDate = new KrogerDate(date.getTime());
    extendedDate.krogerDateString = dateConst.formatPeriodDate(date, false, false, 0);
    this.dateChanged.emit(extendedDate);
    this.shouldEmitDateChangedEvent = true;
  };

  private readonly getValueDate = (value): Date => {
    if (!isNullOrUndefined(value)) {
      return this.validateDateString(dateConst.selectedDateToString(value), true);
    } else {
      return null;
    }
  };

  /** Returns current error status. */
  @Method()
  async isInValidDate() {
    return this.hasError || this.displayError;
  }

  /** Resets date to blank or to the passed in date (string). */
  @Method()
  async reset(date?) {

    // eslint-disable-next-line @stencil/strict-boolean-conditions
    if (typeof date == 'string' && isValidDateString(date)) {
      this._displayError = false;
      this.attemptToSetDate(date);
      this.updateInputWithValue();
      this.resetTime();
    } else {
      this.selectedDate = null;
      this.inputValue = '';
      this.resetTime();
      // Need to call clear on the child masked input to clear when using masked input.
      if (!this.hasPeriodMask) {
        this.hostEl.querySelector('mx-masked-input').clear();
      }
      this._displayError = false;
      this.emitDateChanged(null);
    }
  }

  private readonly toggle = (e: Event, calendar: CalendarType): void => {
    e.preventDefault();
    this.currentCal = calendar;
    if (this.hasPeriodMask) {
      const isGregorian: boolean = this.currentCal === CalendarType.GREGORIAN;
      if (isGregorian) {
        this.inputValue = dateConst.formatDate(this.selectedDate);
      } else {
        this.inputValue = this.formatAdFisDate(false);
      }
    } else {
      if (this.selectedDate != null && !isNullOrUndefinedOrEmptyString(this.inputValue)) {
        this.inputValue = dateConst.formatDate(this.selectedDate);
      }
    }
    // Prevent the focus event from emitting twice under extreme edge cases.
    if (this.open) {
      this.shouldEmitFocusEvent = false;
    }
    this.setOpen(true);
    this.containerElement.querySelector('input').focus();
    this.focused = true;
    this.shouldEmitFocusEvent = true;
  };

  private updateTime(newTime: string) {
    const startTime: ITimeEntry = dateConst.getStartTime(newTime, this._value);
    this.timeEntries = dateConst.getTimeEntries(this.minutesIncrement);

    let selectedTimeEntry = this.timeEntries.find((te: any) => {
      return startTime && isEqual(startTime.hour, te.value.hour) && isEqual(startTime.minute, te.value.minute);
    });
    // TODO: Fix typing issue.
    this.timeValue = selectedTimeEntry ? selectedTimeEntry : this.timeEntries[0];
  }

  private readonly setOpen = (open: boolean): void => {
    this.open = open;
  };

  private readonly inputClickHandler = (): void => {
    this.focusHandler(null);
  };

  private readonly focusHandler = (e: FocusEvent): void => {
    if (this.currentCal === CalendarType.AD || this.currentCal === CalendarType.FISCAL) {
      if (!isNullOrUndefined(this.selectedDate)) {
        this.year = Number(this.formatAdFisDate(false).slice(0, 4));
      } else if (!isNullOrUndefined(this.visualSelectedDate)) {
        this.year = Number(this.formatAdFisDate(false).slice(0, 4));
      } else {
        this.year = new Date().getFullYear();
      }
    } else {
      if (!isNullOrUndefined(this.selectedDate)) {
        this.year = this.selectedDate.getFullYear();
      } else if (!isNullOrUndefined(this.visualSelectedDate)) {
        const visualDate = new Date(this.visualSelectedDate);
        this.year = visualDate.getFullYear();
        this.month = dateConst.monthNames[visualDate.getMonth()];
      }
    }
    this.setOpen(true);
    if (this.shouldEmitFocusEvent) {
      this.dateFocus.emit(e);
    }
    this.focused = true;
    this._displayError = false;
    this.errorString = '';
    // If the date is empty when opening up the calendar, then it should show the current date
    if (isNullOrUndefined(this.selectedDate) && isNullOrUndefined(this.visualSelectedDate)) {
      this.setInitialMonthAndYear();
    }
  };

  private readonly blurHandler = (): void => {
    this.focused = false;
  };

  private readonly calendarBlur = (): void => {
    this.focused = false;
    this.dateBlur.emit(this.inputValue);
    this.attemptToSetDate(this.inputValue);
    this.setOpen(false);
  };

  private readonly inputHandler = (e: MxMaskedInputCustomEvent<string>): void => {
    if (this.selectedDate != null) {
      this.selectedDate = null;
      this.emitDateChanged(null);
    }
    this.inputValue = e.detail;
    this.dateInput.emit(e.detail);
  };

  private readonly changeHandler = (e: MxMaskedInputCustomEvent<string>): void => {
    if (!this.open) {
      this.setOpen(false);
      this.validateEmpty(this.inputValue);
      this.attemptToSetDate(e.detail);
    }
  };

  private readonly setTypedInFiscalDate = (inputValue: string) => {
    if (!this.disableKeyInput &&
      !this.disabled &&
      this.hasPeriodMask &&
      this.currentCal === CalendarType.FISCAL) {
      this.inputValue = inputValue;
      if (this.timeValue) {
        inputValue += ` ${this.timeValue.value['hour']}:${this.timeValue.value['minute']}`;
      }
      const date: Date | string = this.formatDateString(inputValue);
      if (this.open) {
        this.setOpen(false);
      }
      if (date == null) {
        this.displayError = true;
        this.errorString = this.invalidDateErrorMessage;
        return;
      }
      this.selectedDate = date as Date;
      this.emitDateChanged(date as Date);
    }
  }

  private readonly attemptToSetDate = (inputString: string, focused: boolean = false): void => {

    this.displayError = false;

    // eslint-disable-next-line @stencil/strict-boolean-conditions
    if (this.hasPeriodMask && this.currentCal !== CalendarType.FISCAL && !inputString.match(this.dateRegExp)) {
      return;
    }

    const date: Date = this.validateDateString(inputString);

    if (date == null) {
      return;
    }

    const validationResult: DateValidationResult =
      dateConst.validateMinMax(date, this._minActiveDate, this._maxActiveDate, true);

    this.errorString = validationResult.message;
    if (!validationResult.valid) {
      this._displayError = true;
      this.resetTime();
      return null;
    }

    if (!dateConst.isSameDate(this.selectedDate, date)) {
      if (this.hideGregorian && (this.hideAdDays || this.hideFiscalDays) && (this.showFiscal || this.showAd)) {
        const weekDay: number = date.getDay();
        if (this.customOffset !== weekDay) {
          this.displayError = true;
          this.errorString =
            `Selected date is '${dateConst.daysOfWeekFullNames[weekDay]}' and does not match custom offset.
            It should be '${dateConst.daysOfWeekFullNames[this.customOffset]}'`;
          return;
        }
      }
      this.setTime(date);
      this.month = dateConst.monthNames[date.getMonth()];
      this.year = date.getFullYear();
      this.selectedDate = date;
      this.emitDateChanged(date);
      this.focused = focused;
      this.setOpen(false);
    }
  };

  private readonly validateEmpty = (inputString: string): boolean => {
    if (stringUtils.isBlank(inputString) && this.enableErrorValidation) {
      console.warn('Date is empty');
      this.errorString = this.invalidDateErrorMessage;
      this._displayError = true;
      this.resetTime();
      return false;
    }
    return true;
  };

  // method returns date without time (time is defaulted to 00:00)
  private readonly validateDateString = (inputString: string, renderValue = false): Date => {
    if (stringUtils.isBlank(inputString)) {
      return null;
    }

    const newDate = this.formatDateString(inputString.trim());

    if (newDate instanceof Date) {
      return newDate;
    }
    const dateString = inputString.slice(0, 10);
    const [month, day, year] = dateString.split('/');

    const monthNum: number = parseInt(month, 10) - 1;
    const yearNum: number = parseInt(year, 10);
    const dayOfMonth: number = parseInt(day, 10);

    const errorMessage: string = `Cannot submit date: ${inputString}`;

    if (dateConst.datePartsInvalid(yearNum, monthNum, dayOfMonth)) {
      console.warn(errorMessage);
      this.errorString = this.invalidDateErrorMessage;
      this._displayError = true;
      this.resetTime();
      return null;
    }

    // eslint-disable-next-line max-len
    const numOfDaysInCurrentMonth: number = (monthNum === 12 ? new Date(yearNum + 1, 1, 0) : new Date(yearNum, monthNum + 1, 0)).getDate();

    if (numOfDaysInCurrentMonth < dayOfMonth) {
      // eslint-disable-next-line max-len
      const warnMessage: string = `There are max ${numOfDaysInCurrentMonth} days in ${dateConst.monthNames[monthNum]} in ${yearNum}`;
      console.warn(warnMessage);
      this.errorString = this.invalidDateErrorMessage;
      this._displayError = true;
      if (renderValue) {
        this.inputValue = inputString;
      }
      return null;
    }

    const date: Date = new Date(yearNum, monthNum, dayOfMonth, 0, 0, 0, 0);

    if (dateConst.dateIsInvalid(date)) {
      console.warn(errorMessage);
      this.errorString = this.invalidDateErrorMessage;
      this._displayError = true;
      this.resetTime();
      return null;
    }

    const validationResult: DateValidationResult =
      dateConst.validateMinMax(date, this._minActiveDate, this._maxActiveDate, true);

    this.errorString = validationResult.message;
    if (!validationResult.valid) {
      this._displayError = true;
      this.resetTime();
      return null;
    }

    return date;
  };

  private readonly selectDate = async (e: MxCalendarCustomEvent) => {
    let date: Date = e.detail;

    if (date == null) {
      await this.reset(null);
      this.setInitialMonthAndYear();
      return;
    }

    this.setTime(date);
    const sameDate: boolean = dateConst.isSameDate(this.selectedDate, date);

    if (sameDate) {
      this.setOpen(false);
      this.dateBlur.emit(this.inputValue);
      return;
    }

    if ((this.currentCal === CalendarType.AD && this.hideAdDays) ||
      (this.currentCal === CalendarType.FISCAL && this.hideFiscalDays)) {
      const dateValidationResult: DateValidationResult =
        dateConst.validateMinMax(date, this._minActiveDate, this._maxActiveDate, true);

      if (!dateValidationResult.valid && dateValidationResult.minAvailableDate != null) {
        date = dateValidationResult.minAvailableDate;
      }
    }

    if (dateConst.validateMinMax(date, this._minActiveDate, this._maxActiveDate, true).valid) {
      const dateYear = date.getFullYear();
      this._displayError = false;
      this.selectedDate = date;
      this.emitDateChanged(this.selectedDate);
      this.focused = false;
      this.setOpen(false);
      this.updateInputWithValue();
      this.updateYearsRangeIfNecessary(dateYear);
      this.dateBlur.emit(this.inputValue);
      this.year = dateYear;
      this.month = dateConst.monthNames[date.getMonth()];

      if (this.currentCal === CalendarType.AD || this.currentCal === CalendarType.FISCAL) {
        this.years = dateConst.composeYearList(this._minActiveDate, this._maxActiveDate, dateYear);
      }
    }
  };

  private readonly setTime = (date: Date): void => {
    if (date == null || dateConst.dateIsInvalid(date) || this.timeValue == null) {
      return;
    }
    const selectedDate: any = this.timeValue.value;
    date.setHours(parseInt(selectedDate.hour, 10));
    date.setMinutes(parseInt(selectedDate.minute, 10));
  };

  private readonly timeChangeHandler = (e: CustomEvent<Item>): void => {
    this.timeValue = this.timeEntries.find((te: Item) => isEqual(e.detail.value, te.value));
    if (!isNullOrUndefined(this.selectedDate)) {
      this.setTime(this.selectedDate);
      this.emitDateChanged(this.selectedDate);
      this.focused = false;
    }
  };

  private readonly dropDownOpenHandler = (): void => {
    // Is there a selected item? If so scroll to it...
    if (this.containerElement.querySelector('.mx-selected')) {
      // @ts-ignore
      const offsetTop = this.containerElement.querySelector('.mx-selected').offsetTop;
      this.containerElement.querySelector('.view-port').scrollTop = offsetTop;
    }
  };

  private readonly updateInputWithValue = (): void => {
    if (!isNullOrUndefined(this.selectedDate)) {
      if (this.hasPeriodMask) {
        const isGregorian: boolean = this.currentCal === CalendarType.GREGORIAN;
        if (isGregorian) {
          this.inputValue = dateConst.formatDate(this.selectedDate);
          return;
        }
        this.inputValue = this.formatAdFisDate(false);
        return;
      }
      this.inputValue = dateConst.formatDate(this.selectedDate);
    }
  };

  private readonly setInitialMonthAndYear = (): void => {
    const valueDate = this.getValueDate(this.value);
    const visualDate = this.getValueDate(this.visualSelectedDate);
    const initialDate: Date = valueDate || visualDate || new Date();
    this.month = dateConst.monthNames[initialDate.getMonth()];
    this.year = initialDate.getFullYear();
  };

  private readonly resetTime = (): void => {
    this.timeValue = null;
  };

  private readonly determineOpenDirection = (): void => {
    if (this.containerElement && this.ddElement && this.open && this.enableDropUp) {
      const ddHeight: number = this.ddElement.offsetHeight;
      const elementOffset = getOffset(this.containerElement);
      const spaceBelow: number = window.innerHeight - elementOffset.bottom;
      this.openUp = spaceBelow <= ddHeight;
    }
  };

  private readonly formatAdFisDate = (addPrefix = true): string => {
    const isGregorian: boolean = this.currentCal === CalendarType.GREGORIAN;
    if (isGregorian) {
      return '';
    }

    const isFiscal: boolean = this.currentCal === CalendarType.FISCAL;
    const dateOffset: number = isFiscal ? 0 : 3;

    const hideDays: boolean = (isFiscal && this.hideFiscalDays) || (!isFiscal && this.hideAdDays);

    const prefix: string = `${isFiscal ? 'Fis ' : 'Ad '}`;

    const formattedPeriod: string = dateConst.formatPeriodDate(
      this.selectedDate, hideDays, this.showFiscalWeek, dateOffset);
    return `${addPrefix ? prefix : ''}${formattedPeriod}`;
  };

  private readonly updateYearsRangeIfNecessary = (year: number): void => {
    const firstYear: number = parseInt(this.years[0].value as string, 10);
    const lastYear: number = parseInt(this.years[this.years.length - 1].value as string, 10);

    if (year < firstYear || year > lastYear) {
      this.years = dateConst.rangeIncluding(year - 2, year + 3)
        .map((r) => ({ label: r + '', value: r + '' }));
    }
  };

  private readonly escHandler = (e: KeyboardEvent): void => {
    if (e.code === 'Escape') {
      this.setOpen(false);
    }
  };

  private readonly enterHandler = (e: KeyboardEvent): void => {
    if (e.code === 'Enter') {
      e.preventDefault();
      this.setOpen(false);
      this.attemptToSetDate(this.inputValue, true);
    }
  };

  private readonly handleGregorianMonthChange = (e: CustomEvent<{ newMonth: number, oldMonth: number }>) => {
    const { newMonth, oldMonth } = e.detail;

    const movingToNextYear = oldMonth === 11 && newMonth === 0;
    const movingToPrevYear = oldMonth === 0 && newMonth === 11;

    // Only update the year if we're crossing the year boundary
    this.month = dateConst.monthNames[newMonth];
    if (movingToNextYear) {
      this.year += 1;
      this.updateYearsRangeIfNecessary(this.year);
    } else if (movingToPrevYear) {
      this.year -= 1;
      this.updateYearsRangeIfNecessary(this.year);
    }
  };

  private readonly handleGregorianYearChange = (e: CustomEvent<{ value: string }>) => {
    this.year = parseInt(e.detail.value, 10);
    this.updateYearsRangeIfNecessary(this.year);
  };

  private readonly renderHintText = (hasError) => (
    <div class={`${!this.isInQueryPanel ? 'mb-4' : 'mb-8'} mx-date-picker__hint-text`}>
      <kds-text class={{ 'text-negative-less-prominent': hasError }}>{this.hintText}</kds-text>
    </div>
  )

  private readonly renderGregorianButton = (buttonClassesObject, isGregorian) => (
    this.hideGregorian ? null : <kds-button
      class={buttonClassesObject}
      type='button'
      onFocusin={() => this.gregorianBtnFocused = true}
      onFocusout={() => this.gregorianBtnFocused = false}
      palette='accent'
      kind={!isGregorian ? 'subtle' : 'prominent'}
      variant={isGregorian ? 'fill' : 'border'}
      compact={true}
      disabled={this.disabled}
      onClick={(e) => this.toggle(e, CalendarType.GREGORIAN)}>
      <kds-icon-calendar />
    </kds-button>
  )

  private readonly renderAdButton = (buttonClassesObject, isAd) => (

    this.showAd ? <kds-button
      class={buttonClassesObject}
      type='button'
      kind={!isAd ? 'subtle' : 'prominent'}
      palette='accent'
      variant={isAd ? 'fill' : 'border'}
      onFocusin={() => this.adBtnFocused = true}
      onFocusout={() => this.adBtnFocused = false}
      compact={true}
      disabled={this.disabled}
      onClick={(e) => this.toggle(e, CalendarType.AD)}>
      <kds-icon-calendar-ad />
    </kds-button> : null
  )

  private readonly renderFiscalButton = (buttonClassesObject, isFiscal) => (

    this.showFiscal ? <kds-button
      class={buttonClassesObject}
      type='button'
      compact={true}
      disabled={this.disabled}
      palette='accent'
      kind={!isFiscal ? 'subtle' : 'prominent'}
      variant={isFiscal ? 'fill' : 'border'}
      onFocusin={() => this.fiscalBtnFocused = true}
      onFocusout={() => this.fiscalBtnFocused = false}
      onClick={(e) => this.toggle(e, CalendarType.FISCAL)}>
      <kds-icon-calendar-fiscal />
    </kds-button> : null
  )

  private readonly renderCalendars = (isGregorian) => (
    isGregorian ?
      <mx-gregorian-calendar
        onCalendarBlur={this.calendarBlur}
        onSelectDate={this.selectDate}
        onReady={this.determineOpenDirection}
        year={this.year}
        years={this.years}
        month={this.month}
        disabled={this.disabled}
        onMonthChange={this.handleGregorianMonthChange}
        onYearChange={this.handleGregorianYearChange}
        minActiveDate={this._minActiveDate}
        maxActiveDate={this._maxActiveDate}
        value={this.selectedDate} /> :
      <mx-ad-fiscal-calendar
        onCalendarBlur={this.calendarBlur}
        onSelectDate={this.selectDate}
        onReady={this.determineOpenDirection}
        year={this.year}
        years={this.years}
        disabled={this.disabled}
        minActiveDate={this._minActiveDate}
        maxActiveDate={this._maxActiveDate}
        calType={this.currentCal}
        hideAdDays={this.hideAdDays}
        hideFiscalDays={this.hideFiscalDays}
        visualSelectedDate={this.visualSelectedDate ? new Date(this.visualSelectedDate) : null}
        customOffset={this.customOffset}
        value={this.selectedDate} />
  )

  render() {
    const hasError: boolean = this.hasError || this.displayError;

    const isGregorian: boolean = this.currentCal === CalendarType.GREGORIAN;
    const isAd: boolean = this.currentCal === CalendarType.AD;
    const isFiscal: boolean = this.currentCal === CalendarType.FISCAL;

    const hideFiscalDaysEffective: boolean = isFiscal && this.hideFiscalDays;
    const hideAdDaysEffective: boolean = isAd && this.hideAdDays;
    const hideDays: boolean = hideFiscalDaysEffective || hideAdDaysEffective;

    const maskedInputDisabled: boolean = this.disableKeyInput || this.disabled;
    const hideDaysPlaceholder = hideDays ? 'YYYY/PP/WW' : 'YYYY/PP/WW/DD';
    const datePlaceholder: string = isGregorian ? 'MM/DD/YYYY' : hideDaysPlaceholder;

    const inputName: string = this.inputName || this.inputId;

    const notDisabledWithPeriodMask: boolean = this.hasPeriodMask && !this.disabled;

    const inputClasses: string[] = [
      'date-picker-input',
      this.disableKeyInput || (notDisabledWithPeriodMask && !isFiscal) ? 'mx-date-picker__period-input' : '',
      this.focused ? 'border-brand-less-prominent' : '',
      hasError ? 'border-negative-less-prominent' : '',
      hasError && this.focused ? 'border-negative-less-prominent' : '',
      this.disableKeyInput ? 'bg-quaternary-fill text-placeholder' : 'text-primary'
    ];

    const buttonClassesObject = {
      'mx-date-picker__icon': true,
      'border-accent-less-prominent': this.focused,
      'border-negative-less-prominent': hasError && !this.focused,
      'mx-date-picker__icon_compact': this.compact
    };

    return (
      <div
        ref={(el) => this.containerElement = el}
        class={{
          'mx-date-picker': true,
          'mx-date-picker_disabled': this.disabled
        }}>

        {!this.hideLabels && (
          <Fragment>
            <kds-label class={{
              'mb-8 mt-16 font-base body-m font-700 mx-date-picker__date-label': true,
              'text-negative-less-prominent': hasError
            }}>
              <span class={{ 'text-primary': !hasError }}>{this.label}</span>
              {
                !isGregorian && this.selectedDate && (this.showAd || this.showFiscal) && (
                  <span class={{
                    'mx-date-picker__optional-text': true,
                    'text-secondary': !hasError
                  }}>{this.formatAdFisDate()}</span>
                )
              }
            </kds-label>
            {
              this.showTime && !this.isInQueryPanel && (
                <kds-label class='mb-8 font-base body-m font-700 mt-16 mx-date-picker__time-label'>
                  <span class={{ 'text-primary': !hasError }}>{this.timeLabel}</span>
                </kds-label>
              )
            }
          </Fragment>
        )}

        <div class='mx-date-picker__inputs-container'>
          <div class='mx-date-picker__date' ref={(el) => this.inputWrapper = el}>
            <div
              class={{
                'mx-date-picker__date-input': true,
                'mx-date-picker__date-input_focused': this.focused,
                'mx-date-picker__date-input_has-error': hasError,
                'mx-date-picker__date-input_keys-disabled': this.disableKeyInput || this.hasPeriodMask
              }}>
              {
                notDisabledWithPeriodMask ?
                  <kds-input
                    name={inputName}
                    input-id={this.inputId}
                    inputClass={inputClasses.join(' ')}
                    value={this.inputValue}
                    placeholder={datePlaceholder}
                    maxlength={datePlaceholder.length + 2}
                    has-error={hasError}
                    onKeyDown={(e: KeyboardEvent) => {
                      this.escHandler(e);
                      const pressedKey: string = e.key;
                      if (!this.disableKeyInput && this.currentCal === CalendarType.FISCAL) {
                        const inputElement: HTMLInputElement = e.target as HTMLInputElement;
                        const selStart: number = inputElement.selectionStart;
                        const selEnd: number = inputElement.selectionEnd;
                        const currentValue: string = inputElement.value;
                        const navigationKey: boolean = eventUtils.navigationKeys.includes(pressedKey);
                        const controlKeys: boolean = eventUtils.controlKeys.includes(pressedKey);
                        const meta: boolean = e.metaKey && eventUtils.metaAddonKeys.includes(pressedKey.toUpperCase());
                        const valid: boolean = navigationKey || meta || controlKeys ?
                          this.validateNotFilledFiscalDateString(currentValue) :
                          this.validAfterInput(selStart, selEnd, currentValue, pressedKey);
                        if (!(navigationKey || meta) && !valid) {
                          e.preventDefault();
                        }

                        if (pressedKey === 'Enter') {
                          this.setTypedInFiscalDate(currentValue);
                          this.focused = false;
                          this.setOpen(false);
                        }
                        return;
                      }

                      if (pressedKey !== 'Tab') {
                        e.preventDefault();
                      }
                    }}
                    onClick={this.inputClickHandler}
                    onFocusin={this.focusHandler}
                    onFocusout={this.blurHandler}
                    compact={this.compact} /> :
                  <mx-masked-input
                    input-name={inputName}
                    input-class={inputClasses.join(' ')}
                    mask='MM/DD/YYYY'
                    maxLength={11}
                    isClearable={false}
                    input-id={this.inputId}
                    value={this.inputValue}
                    disabled={maskedInputDisabled}
                    has-error={hasError}
                    compact={this.compact}
                    onClick={() => {
                      if (this.disableKeyInput) {
                        this.focusHandler(null);
                      }
                    }}
                    onKeyDown={(e: KeyboardEvent) => {
                      this.escHandler(e);
                      this.enterHandler(e);
                    }}
                    onFocusin={this.focusHandler}
                    onFocusout={this.blurHandler}
                    onMaskedInput={this.inputHandler}
                    onMaskedChange={this.changeHandler}
                    display-error={this.displayError} />
              }
              {this.open ?
                <div
                  ref={(el) => this.ddElement = el}
                  class={{
                    'border-neutral-less-subtle': true,
                    'mx-date-picker__dropdown': true,
                    'mx-date-picker__dropdown_up': this.openUp,
                    'mx-date-picker__dropdown_down': !this.openUp
                  }}>
                  {this.renderCalendars(isGregorian)}
                </div> : <span />}
              <div class={{
                'mx-date-picker__icons': true,
                'mx-date-picker__icons_focused': this.focused,
                'mx-date-picker__icons_error': hasError
              }}>
                {this.renderGregorianButton(buttonClassesObject, isGregorian)}
                {this.renderAdButton(buttonClassesObject, isAd)}
                {this.renderFiscalButton(buttonClassesObject, isFiscal)}
              </div>
            </div>
          </div>
          {this.showTime && !this.isInQueryPanel ? (
            <div class='mx-date-picker__time'>
              <div class='mx-date-picker__time-input'>
                <mx-single-select
                  isDisabled={this.disabled}
                  itemSelected={this.timeValue}
                  items={this.timeEntries}
                  is-compact={this.compact}
                  onDropdownOpen={this.dropDownOpenHandler}
                  onItemChange={this.timeChangeHandler}
                  enableDropUp={this.enableDropUp}
                  width='120px'
                  list-width='100%' />
              </div>
            </div>
          ) : <span />}
        </div>
        {this.isInQueryPanel && this.renderHintText(hasError)}

        {
          this.showTime && this.isInQueryPanel && (
            <kds-label class='mb-8 font-base body-m font-700 mx-date-picker__time-label'>
              <span class={{ 'text-primary': !hasError }}>{this.timeLabel}</span>
            </kds-label>
          )
        }

        {this.showTime && this.isInQueryPanel && (<div class='mx-date-picker__inputs-container'>
          <div class='mx-date-picker__time'>
            <div class='mx-date-picker__time-input'>
              <mx-single-select
                isDisabled={this.disabled}
                itemSelected={this.timeValue}
                items={this.timeEntries}
                is-compact={this.compact}
                onDropdownOpen={this.dropDownOpenHandler}
                onItemChange={this.timeChangeHandler}
                enableDropUp={this.enableDropUp}
                width='120px'
                list-width='100%' />
            </div>
          </div>
        </div>)}

        {!this.isInQueryPanel && this.renderHintText(hasError)}
        {
          this.displayError ? (
            <div class='mx-date-picker__message mt-4 mb-4 text-negative-less-prominent'>
              <kds-text>{this.errorString}</kds-text>
            </div>
          ) : <span />
        }
      </div>
    );
  }

  private validAfterInput(selectionStart: number, selectionEnd: number, value: string, key: string): boolean {
    const prefix: string = value.substring(0, selectionStart);
    const suffix: string = value.substring(selectionEnd);
    return this.validateNotFilledFiscalDateString(`${prefix}${key}${suffix}`);
  }

  private validateNotFilledFiscalDateString(fiscalDateString: string): boolean {
    fiscalDateString = fiscalDateString.trim();
    if (fiscalDateString == null || fiscalDateString === '') {
      return true;
    }
    const fiscalDateStringParts: string[] = fiscalDateString.split('/');

    if (fiscalDateStringParts.length === 5 || (this.hideFiscalDays && fiscalDateStringParts.length === 4)) {
      return false;
    }

    const yearString: string = fiscalDateStringParts[0];
    const isValidYear: boolean = yearString.length <= 4 && /^\d+$/.test(yearString);

    const periodString: string = fiscalDateStringParts[1];
    const periodNotFilled: boolean = isNullOrUndefinedOrEmptyString(periodString);
    const isValidPeriod: boolean = periodNotFilled ||
      (periodString.startsWith('P') &&
        (periodString.length === 1 ||
          (/^\d+$/.test(periodString.slice(1)) &&
            Number(periodString.slice(1)) >= 1 &&
            Number(periodString.slice(1)) <= 13)));

    const weekString: string = fiscalDateStringParts[2];
    const weekNotFilled: boolean = isNullOrUndefinedOrEmptyString(weekString);
    const isValidWeek: boolean = weekNotFilled ||
      (weekString.startsWith('W') && (weekString.length === 1 ||
        (/^\d+$/.test(weekString.slice(1)) &&
          (this.showFiscalWeek && Number(weekString.slice(1)) >= 1 && Number(weekString.slice(1)) <= 4)) ||
          (!this.showFiscalWeek && Number(weekString.slice(1)) >= 1 && Number(weekString.slice(1)) <= 53)));

    const dayString: string = fiscalDateStringParts[3];
    const weekDay1stLetters: string[] = dateConst.daysOfWeek1stLetters as string[];
    const weekDayNames: string[] = dateConst.daysOfWeekNames as string[];
    const dayNotFilled: boolean = isNullOrUndefinedOrEmptyString(dayString);
    const isValidDay: boolean = dayNotFilled ||
      (dayString.length === 1 && (weekDay1stLetters.includes(dayString)) ||
      weekDayNames.includes(dayString));
    return isValidYear && isValidPeriod && isValidWeek && isValidDay;
  }

  private readonly formatDateString = (inputString: string): Date | string => {
    // capital W is week of year and small w is week of period
    const formatString = `<yyyy>/P<p>/W<${this.showFiscalWeek ? 'w' : 'W'}>/D<#d>`;
    const formatter = new KrogerDateFormatter(formatString);
    // Check if the input string matches the Gregorian date format (MM/DD/YYYY or YYYY-MM-DD)
    if (isValidGregorianDateString(inputString)) {
      return inputString; // Return as is if Gregorian format
    }

    // Append a default day of the week if fiscal or ad days are hidden to pass the check
    const weekDayName: string = dateConst.daysOfWeekNames[this.hideFiscalDays ? this.customOffset : 0];
    const inputStringWithDefaultDay = `${inputString}/${weekDayName}`;
    const stringToValidate: string = (this.currentCal === CalendarType.FISCAL && this.hideFiscalDays) ||
    (this.currentCal === CalendarType.AD && this.hideAdDays) ? inputStringWithDefaultDay : inputString;
    // Check if the input string matches the Fiscal date format (yyyy/Ppp/Www/<dayOfWeek>)
    if (isValidFiscalDateString(stringToValidate)) {
      try {
        // Map days of the week to corresponding numbers
        const dayOfWeekMapping: Record<string, number> = {
          Su: 1,
          Mo: 2,
          Tu: 3,
          We: 4,
          Th: 5,
          Fr: 6,
          Sa: 7
        };

        // Extract the day of the week from the input string
        const dayOfWeekMatch = stringToValidate.match(/\/(Su|Mo|Tu|We|Th|Fr|Sa)/);
        if (dayOfWeekMatch) {
          const dayOfWeek = dayOfWeekMatch[1];
          const dayNumber = dayOfWeekMapping[dayOfWeek];

          // Extract time if present (e.g., '8:00' or '08:00')
          const timeMatch = inputString.match(/\b(\d{1,2}):(\d{2})\b/);
          let hours = 0;
          let minutes = 0;
          if (timeMatch) {
            hours = parseInt(timeMatch[1], 10);
            minutes = parseInt(timeMatch[2], 10);
          } else if (this.timeValue && this.timeValue.value) {
            hours = parseInt(this.timeValue.value['hour'], 10);
            minutes = parseInt(this.timeValue.value['minute'], 10);
          }

          // Replace the day of the week with the corresponding number
          const updatedInputString = stringToValidate.replace(/\/(Su|Mo|Tu|We|Th|Fr|Sa)/, `/D${dayNumber}`)
            // Remove the time portion for parsing
            .replace(/\s+\d{1,2}:\d{2}\b/, '');

          // Use KrogerDateFormatter to parse the updated fiscal string into a KrogerDate
          const parsedDate: KrogerDate = formatter.parseKrogerDate(updatedInputString);
          // Create a new Date object from the KrogerDate
          const dateObj = parsedDate.toDate();
          // If time was present, set hours and minutes
          if (timeMatch) {
            dateObj.setHours(hours, minutes, 0, 0);
          }
          return dateObj;
        }
      } catch (error) {
        console.error('Error parsing fiscal date string:', error);
        return null;
      }
    }

    console.warn('Invalid date format:', inputString);
    return null; // Return null if neither format matches
  };
}
